/**
 * Get the completion from the model.
 *
 * @param messages The messages to complete.
 * @param options The options to use for the completion.
 * @returns The completion.
 */
export async function getCompletion(messages: OpenAI.ChatCompletionRequestMessage[], options: OpenAI.ChatCompletionRequest = {}): Promise<OpenAI.ChatCompletionResponse> {
  return ilmuClient.chat.completions.create({
    ...options,
    messages,
  });
}

/**
 * Get the completion from the model.
 *
 * @param messages The messages to complete.
 * @param options The options to use for the completion.
 * @returns The completion.
 */
export async function getChatCompletion(messages: OpenAI.ChatCompletionRequestMessage[], options: OpenAI.ChatCompletionRequest = {}): Promise<OpenAI.ChatCompletionResponse> {
  return ilmuClient.chat.completions.create({
    ...options,
    messages,
  });
}

/**
 * Get the completion from the model.
 *
 * @param system The system message to use.
 * @param user The user message to use.
 * @param options The options to use for the completion.
 * @returns The completion.
 */
export async function getSystemCompletion(system: string, user: string, options: OpenAI.ChatCompletionRequest = {}): Promise<OpenAI.ChatCompletionResponse> {
  return ilmuClient.chat.completions.create({
    ...options,
    messages: [
      { role: "system", content: system },
